
// Archivo autoextraíble generado por compress.js
// Uso: node backend.js --key TU_KEY

const fs = require("fs");
const path = require("path");
const crypto = require("crypto");
const minimist = require("minimist");

const args = minimist(process.argv.slice(2));
const KEY = args.key || 'none';
/*if (!KEY) {
  console.error("Missing --key");
  process.exit(1);
}*/

const encryptedB64 = ``;
const ivB64 = "AkKqNa2AnGQGK5J+1eDc2w==";

const encrypted = Buffer.from(encryptedB64, "base64");
const iv = Buffer.from(ivB64, "base64");
const key = crypto.createHash("sha256").update(KEY).digest();

try {
  const decipher = crypto.createDecipheriv("aes-256-cbc", key, iv);
  const decrypted = Buffer.concat([decipher.update(encrypted), decipher.final()]);
  const { files } = JSON.parse(decrypted.toString("utf8"));

  console.log("Restoring backend...");

  for (const relPath of Object.keys(files)) {
    const fullPath = path.join(process.cwd(), relPath);
    const dir = path.dirname(fullPath);

    fs.mkdirSync(dir, { recursive: true });

    const content = Buffer.from(files[relPath], "base64").toString("utf8");
    fs.writeFileSync(fullPath, content, "utf8");

    console.log("✔", relPath);
  }

  console.log("✔ Backend restored successfully.");
} catch (err) {
  console.error("Decrypting error:", err.message);
  console.error("Perhaps you didn't type the password correctly.");
  console.error("You need to send the password using the --key argument to decompress.");
}
